const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

const rawAction = safeText(input.action, 'ensureAndWrite').toLowerCase();
const action = rawAction === 'ensuresheet'
  ? 'ensureSheet'
  : (rawAction === 'writerows' ? 'writeRows' : 'ensureAndWrite');

const spreadsheetId = safeText(input.spreadsheetId);
const spreadsheetName = safeText(input.spreadsheetName, 'untitled-sheet');
const sheetName = safeText(input.sheetName, 'Sheet1');
const folderId = safeText(input.folderId);
const rows = Array.isArray(input.rows) ? input.rows : [];
const writeRange = safeText(input.range, sheetName + '!A1');

const normalizedValueInputOption = safeText(input.valueInputOption, 'RAW').toUpperCase();
const valueInputOption = normalizedValueInputOption === 'USER_ENTERED'
  ? 'USER_ENTERED'
  : 'RAW';

const shouldEnsure = action === 'ensureAndWrite' || action === 'ensureSheet';
const shouldWrite = action === 'ensureAndWrite' || action === 'writeRows';
const shouldMove = shouldEnsure && folderId !== '';
const shouldCreateSheet = shouldEnsure && spreadsheetId === '';
const missingSpreadsheetIdForWrite = action === 'writeRows' && spreadsheetId === '';
const shouldCallWriteApi = shouldWrite && !missingSpreadsheetIdForWrite;

return {
  ...input,
  action,
  spreadsheetId,
  spreadsheetName,
  sheetName,
  folderId,
  rows,
  writeRange,
  valueInputOption,
  shouldEnsure,
  shouldWrite,
  shouldMove,
  shouldCreateSheet,
  missingSpreadsheetIdForWrite,
  shouldCallWriteApi,
};

