const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

const body = input.body && typeof input.body === 'object' ? input.body : {};
const spreadsheetId = safeText(body.spreadsheetId, safeText(input.spreadsheetId));
const spreadsheetUrl = safeText(
  body.spreadsheetUrl,
  safeText(input.spreadsheetUrl, spreadsheetId ? 'https://docs.google.com/spreadsheets/d/' + spreadsheetId : ''),
);

const createStatusCodeRaw = Number(input.statusCode ?? 0);
const createStatusCode = Number.isFinite(createStatusCodeRaw) ? createStatusCodeRaw : 0;

return {
  ...input,
  spreadsheetId,
  spreadsheetUrl,
  createStatusCode,
};

const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

const spreadsheetId = safeText(input.spreadsheetId);
const spreadsheetUrl = safeText(input.spreadsheetUrl, spreadsheetId ? 'https://docs.google.com/spreadsheets/d/' + spreadsheetId : '');

const createStatusCodeRaw = Number(input.createStatusCode ?? 0);
const createStatusCode = Number.isFinite(createStatusCodeRaw) ? createStatusCodeRaw : 0;

const writeStatusCodeRaw = Number(input.statusCode ?? 0);
const writeStatusCode = Number.isFinite(writeStatusCodeRaw) ? writeStatusCodeRaw : 0;

const writeOk = input.shouldWrite !== true
  ? true
  : (input.missingSpreadsheetIdForWrite === true
      ? false
      : (writeStatusCode >= 200 && writeStatusCode < 300));
const ensureOk = input.shouldEnsure !== true || spreadsheetId !== '';
const moveStatus = input.shouldMove === true ? 'success' : 'skipped';

return {
  ...input,
  status: ensureOk && writeOk ? 'success' : 'partial',
  spreadsheetId,
  spreadsheetUrl,
  createStatusCode,
  writeStatusCode,
  writeRange: safeText(input.writeRange),
  moveStatus,
};
